<template>
  <div class="products-category mt-10">
    <h1 class="text-center mt-13">{{ route.query.title }}</h1>
    <v-container>
      <v-card class="pt-5" min-height="700" elevation="0">
        <v-row v-if="loading">
          <v-col cols="3" v-for="num in 4" :key="num">
            <v-skeleton-loader type="image,article,button"></v-skeleton-loader>
          </v-col>
        </v-row>
        <v-row v-if="!loading">
          <v-col
            v-for="item in categories"
            :key="item.id"
            cols="12"
            sm="6"
            md="4"
            lg="3"
            class="px-10 px-sm-5 mt-8 mt-lg-0"
          >
            <v-lazy>
              <v-card elevation="0" class="pb-5">
                <v-hover v-slot="{ isHovering, props }">
                  <div
                    class="img-parent position-relative"
                    style="height: 200px; overflow: hidden"
                  >
                    <img
                      :src="
                        showenItem[item.title]
                          ? showenItem[item.title]
                          : item.thumbnail
                      "
                      :alt="item.thumbnail"
                      class="w-100 cursor-pointer"
                      :style="`height: 100%; transition: 0.5s all ease-in-out; scale:${
                        isHovering ? 1.05 : 1
                      }`"
                      v-bind="props"
                    />
                    <v-btn
                      density="compact"
                      width="90"
                      height="30"
                      variant="outlined"
                      rounded="xl"
                      class="bg-white position-absolute quick-view-btn opacity-0"
                      style="
                        text-transform: none;
                        left: 50%;
                        top: 50%;
                        transform: translate(-50%, -50%);
                        font-size: 12px;
                        transition: 0.2s all ease-in-out;
                      "
                      @click="openQuickView(item)"
                      >Quick View</v-btn
                    >
                  </div>
                </v-hover>
                <v-card-text class="pl-0 pb-1">
                  {{
                    `(${item.title}) ${item.description}`.length <= 57
                      ? `(${item.title}) ${item.description}`
                      : `(${item.title}) ${item.description}`.substring(0, 57) +
                        "..."
                  }}
                </v-card-text>
                <v-rating
                  v-model="item.rating"
                  half-increments
                  readonly
                  color="yellow-darken-2"
                  size="x-small"
                  density="compact"
                ></v-rating>
                <v-card-text class="pl-0 pt-0">
                  <del>${{ item.price }}</del> From
                  <v-chip
                    color="red"
                    class="font-weight-black text-subtitle-1"
                    variant="text"
                    >${{
                      Math.floor(
                        item.price -
                          (item.price * item.discountPercentage) / 100
                      )
                    }}</v-chip
                  >
                </v-card-text>
                <v-btn-toggle v-model="showenItem[item.title]">
                  <v-btn
                    v-for="(pic, i) in item.images"
                    :key="i"
                    :value="pic"
                    size="x-small"
                    rounded="xl"
                    :ripple="false"
                    class="overflow-hidden"
                  >
                    <img
                      :src="pic"
                      alt=""
                      width="30"
                      height="30"
                      style="
                        border-radius: 50%;
                        border: 1px solid rgb(135, 135, 135);
                      "
                    />
                  </v-btn>
                </v-btn-toggle>
                <div class="mt-5">
                  <v-btn
                    rounded
                    variant="outlined"
                    density="compact"
                    class="py-5 px-9 d-flex justify-center align-center"
                    @click="
                      $router.push({
                        name: 'product_details',
                        query: { productId: item.id },
                      })
                    "
                    >Choose Options</v-btn
                  >
                </div>
              </v-card>
            </v-lazy>
          </v-col>
        </v-row>
      </v-card>
    </v-container>
  </div>
</template>

<script setup>
import { productsModule } from "@/stores/Products";
import { onMounted, ref } from "vue";
import { useRoute, useRouter } from "vue-router";
import { watch } from "vue";
import { computed } from "vue";
import { VSkeletonLoader } from "vuetify/lib/components";
// Variables Down Below
const route = useRoute();
const store = productsModule();
const showenItem = ref({});
const loading = ref(false);
// Functions DownBelow
onMounted(async () => {
  if (!route.query.category) {
    return useRouter().go(-1);
  }
  loading.value = true;
  await store.getProductsByCategory(route.query.category);
  loading.value = false;
});

watch(
  () => route.query.category,
  async (newCategory, oldCategory) => {
    if (newCategory === oldCategory) return;
    loading.value = true;
    await store.getProductsByCategory(newCategory);
    loading.value = false;
    document.documentElement.scrollTo(0, 0);
    // console.log("Fired");
  }
);
//
const categories = computed(() => store.categoryProducts.products);
// Config Emitter
import { inject } from "vue";
const emitter = inject("emitter");
const openQuickView = (product) => emitter.emit("OpenQuickView", product);
</script>

<style>
.img-parent:hover .quick-view-btn {
  opacity: 1 !important;
}
</style>
